parameters.jsCode:
// Récupérer les données de chaque étape
const vars     = $('Set — Variables entrée').item.json;
const client   = $('Supabase — Profil client').item.json[0];
const dossier  = $('Supabase — Données dossier').item.json[0];
const leadData = $('Supabase — Avocat référent').item.json[0];
const avocat   = leadData?.avocats ?? { full_name: 'Maison Aldéric', email: 'contact@maison-alderic.be', title: 'Cabinet' };

const today = new Date().toLocaleDateString('fr-BE', { day: 'numeric', month: 'long', year: 'numeric' });

// Template HTML du mandat
const html = `
<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Georgia, serif; color: #1A1A1A; max-width: 800px; margin: 40px auto; padding: 40px; }
    .header { border-bottom: 2px solid #1A1A1A; padding-bottom: 20px; margin-bottom: 30px; }
    .cabinet-name { font-size: 22px; font-weight: 500; letter-spacing: -0.02em; }
    .cabinet-sub { font-size: 11px; text-transform: uppercase; letter-spacing: 0.1em; color: #8B887F; margin-top: 4px; }
    .title { font-size: 18px; font-weight: 500; margin: 30px 0 20px; text-align: center; }
    .section { margin: 20px 0; }
    .section h3 { font-size: 11px; text-transform: uppercase; letter-spacing: 0.08em; color: #5C5A55; margin-bottom: 8px; border-bottom: 1px solid #E5E2DB; padding-bottom: 6px; }
    .field { margin: 8px 0; font-size: 13px; }
    .label { font-weight: 500; }
    .signature-block { margin-top: 60px; display: flex; justify-content: space-between; }
    .sig-box { width: 45%; }
    .sig-line { border-top: 1px solid #1A1A1A; margin-top: 60px; padding-top: 8px; font-size: 11px; color: #5C5A55; }
    .footer { margin-top: 40px; font-size: 10px; color: #8B887F; text-align: center; border-top: 1px solid #E5E2DB; padding-top: 16px; }
    .ref { font-size: 10px; color: #8B887F; text-align: right; margin-bottom: 30px; }
  </style>
</head>
<body>
  <div class="header">
    <div class="cabinet-name">Maison Aldéric &amp; Associés</div>
    <div class="cabinet-sub">SCRL · Avenue Louise 480 · 1050 Bruxelles</div>
  </div>

  <div class="ref">Réf. ${dossier?.reference ?? 'N/A'} · ${today}</div>

  <div class="title">LETTRE DE MISSION</div>

  <div class="section">
    <h3>Le cabinet</h3>
    <div class="field"><span class="label">Dénomination :</span> Maison Aldéric &amp; Associés SCRL</div>
    <div class="field"><span class="label">Siège social :</span> Avenue Louise 480, 1050 Bruxelles</div>
    <div class="field"><span class="label">Avocat référent :</span> ${avocat.full_name}, ${avocat.title}</div>
    <div class="field"><span class="label">Contact :</span> ${avocat.email}</div>
  </div>

  <div class="section">
    <h3>Le client</h3>
    <div class="field"><span class="label">Nom :</span> ${client?.full_name ?? 'N/A'}</div>
    <div class="field"><span class="label">Société :</span> ${client?.company ?? '—'}</div>
    <div class="field"><span class="label">E-mail :</span> ${client?.email ?? 'N/A'}</div>
    <div class="field"><span class="label">Téléphone :</span> ${client?.phone ?? '—'}</div>
  </div>

  <div class="section">
    <h3>La mission</h3>
    <div class="field"><span class="label">Dossier :</span> ${dossier?.title ?? 'N/A'}</div>
    <div class="field"><span class="label">Type :</span> ${dossier?.type ?? 'N/A'}</div>
    <div class="field"><span class="label">Description :</span> ${dossier?.description ?? 'Conseil juridique selon les modalités convenues.'}</div>
  </div>

  <div class="section">
    <h3>Conditions générales</h3>
    <div class="field">Les honoraires sont facturés selon le barème convenu. Toute contestation relève de la juridiction compétente du barreau de Bruxelles. Le cabinet est soumis au secret professionnel conformément aux règles déontologiques du Barreau de Bruxelles.</div>
  </div>

  <div class="signature-block">
    <div class="sig-box">
      <div class="sig-line">Pour Maison Aldéric &amp; Associés<br>${avocat.full_name}</div>
    </div>
    <div class="sig-box">
      <div class="sig-line">Pour le client<br>${client?.full_name ?? ''}</div>
    </div>
  </div>

  <div class="footer">
    Maison Aldéric &amp; Associés SCRL · TVA BE 0xxx.xxx.xxx · Barreau de Bruxelles<br>
    Avenue Louise 480, 1050 Bruxelles · contact@maison-alderic.be
  </div>
</body>
</html>`;

return [{
  json: {
    html,
    client_id:    vars.client_id,
    dossier_id:   vars.dossier_id,
    reference:    dossier?.reference ?? 'MANDAT',
    client_email: client?.email,
    client_name:  client?.full_name,
    avocat_email: avocat.email,
    avocat_name:  avocat.full_name,
    filename:     `mandat-${dossier?.reference ?? 'MA'}-${Date.now()}.html`,
    file_path:    `${vars.dossier_id}/mandat-${dossier?.reference ?? 'MA'}-${Date.now()}.html`
  }
}];

parameters.jsonBody:
={
  "from": "Maison Aldéric <mandats@maison-alderic.be>",
  "to": ["{{ $('Code — Génère HTML mandat').item.json.client_email }}"],
  "subject": "Votre lettre de mission — Dossier {{ $('Code — Génère HTML mandat').item.json.reference }}",
  "html": "<p>Bonjour {{ $('Code — Génère HTML mandat').item.json.client_name }},</p><p>Veuillez trouver ci-joint votre lettre de mission pour le dossier <strong>{{ $('Code — Génère HTML mandat').item.json.reference }}</strong>.</p><p>Merci de nous retourner ce document signé.</p><p>Cordialement,<br><strong>{{ $('Code — Génère HTML mandat').item.json.avocat_name }}</strong><br>Maison Aldéric & Associés</p>"
}

={
  "from": "Portail interne <noreply@maison-alderic.be>",
  "to": ["{{ $('Code — Génère HTML mandat').item.json.avocat_email }}"],
  "subject": "[ACTION] Mandat envoyé — {{ $('Code — Génère HTML mandat').item.json.reference }}",
  "html": "<p>Le mandat pour le dossier <strong>{{ $('Code — Génère HTML mandat').item.json.reference }}</strong> a été généré et envoyé au client <strong>{{ $('Code — Génère HTML mandat').item.json.client_name }}</strong>.</p><p>En attente de signature.</p>"
}
